  import React, { useState, useEffect } from 'react';

function Search() {
    return (
        <div>
        <h1>Search</h1>
        <p>Welcome to the Pet Store</p>
        <p>Here, you will be able to search for any pet</p>
        </div>
    );
}
export default Search;
